//---------------------------Function to insert the created feature under the respective Parent feature STARTS------------------------------/
void MRFBackProfileOperations::InsertFeatureUnderGivenFeature(CATBaseUnknown_var spOnMechFeatureChild, CATBaseUnknown_var spOnMechFeatureOnParent)
{
	CATIMmiUseBasicInsertion_var hBasicInsertion = spOnMechFeatureChild;

	if (!!hBasicInsertion)
		hBasicInsertion->InsertInside(spOnMechFeatureOnParent);
}
