HRESULT MRFBackProfileOperations::InsertInParentRef(const CATIPLMProducts_var &piParentPLMProdRef, const CATIPLMProducts_var &piChildPLMProdRef, CATUnicodeString iInstName, CATIPLMNavInstance_var &opProdInstance)
{
	HRESULT rc = E_FAIL;
	CATIPLMProducts *pPLMProdOnParent = NULL;

	if (NULL_var != piParentPLMProdRef)
	{
		CATIPLMNavInstance_var hNavInst = piParentPLMProdRef;
		if (NULL_var != hNavInst)
		{
			CATIPLMNavReference *pNavRef = NULL;
			rc = hNavInst->GetReferenceInstanceOf(pNavRef);
			if (NULL != pNavRef)
			{
				pNavRef->QueryInterface(IID_CATIPLMProducts, (void**)&pPLMProdOnParent);

				pNavRef->Release();
				pNavRef = NULL;
			}
		}

		if (pPLMProdOnParent == NULL)
		{
			pPLMProdOnParent = piParentPLMProdRef;
			if(pPLMProdOnParent)
				pPLMProdOnParent->AddRef();
		}
	}
 
	if (NULL != pPLMProdOnParent && NULL_var != piChildPLMProdRef)
	{
		CATIPLMNavReference *pChildRef = NULL;
		rc = piChildPLMProdRef->QueryInterface(IID_CATIPLMNavReference, (void**)&pChildRef);
		if (NULL != pChildRef)
		{
			CATIPLMNavReference *pParentRef = NULL;
			rc = pPLMProdOnParent->QueryInterface(IID_CATIPLMNavReference, (void**)&pParentRef);
			if (NULL != pParentRef)
			{
				CATBoolean bBol = TRUE;

				pChildRef->Release();
				pChildRef = NULL;

				pParentRef->Release();
				pParentRef = NULL;
			}
		}
		CATBaseUnknown * iBaseProdInstance = NULL;
		rc = pPLMProdOnParent->AddProduct(piChildPLMProdRef, iBaseProdInstance);

		if (FAILED(rc))
		{
			CATApplicationFrame * pAppFrame = CATApplicationFrame::GetFrame();
			if (NULL == pAppFrame)
				return rc;

			CATDlgWindow * pMainWindow = pAppFrame->GetMainWindow();
			if (NULL == pMainWindow)
				return rc;

			CATDlgNotify * pErrPanel = new CATDlgNotify(pMainWindow, "Warning", CATDlgNfyOK | CATDlgNfyError | CATDlgWndModal);
			if (NULL == pErrPanel)
				return rc;

			// Set the text
			CATUnicodeString usWndTitle = "Warning Message", usMessage;

			usMessage.Append("The Product exists but can not be instanciated under this Context\n");


			pErrPanel->DisplayBlocked(usMessage, usWndTitle);

			pErrPanel->RequestDelayedDestruction(); pErrPanel = NULL;
		}

		if (SUCCEEDED(rc) && NULL != iBaseProdInstance)
		{
			CATIPLMIdentifierSet* pIdentifierSetOnNewRef = NULL;
			rc = piChildPLMProdRef->QueryInterface(IID_CATIPLMIdentifierSet, (void **)&pIdentifierSetOnNewRef);
			if (SUCCEEDED(rc) && NULL != pIdentifierSetOnNewRef)
			{
				//rc = iBaseProdInstance->QueryInterface(IID_CATIPLMNavInstance, (void **)&opProdInstance);
				opProdInstance = iBaseProdInstance;
				if (SUCCEEDED(rc) && NULL_var != opProdInstance)
				{
					iBaseProdInstance->Release();
					iBaseProdInstance = NULL;
				}
				pIdentifierSetOnNewRef->Release();
				pIdentifierSetOnNewRef = NULL;
			}
		}
		else
		{
			cout << "Addition failed" << endl;
			rc = E_FAIL;
		}
		pPLMProdOnParent->Release();
		pPLMProdOnParent = NULL;
	}

	return rc;
}

